using Warehouse;

namespace Warehouse.Tests;

[TestClass]
public class StockLevelTests
{
    private InventoryTracker _tracker = null!;

    [TestInitialize]
    public void Setup() => _tracker = new InventoryTracker();

    [TestMethod]
    public void GetStockLevel_UnknownSku_ReturnsZero()
    {
        Assert.AreEqual(0, _tracker.GetStockLevel("UNKNOWN-001"));
    }

    [TestMethod]
    public void AddStock_SingleAdd_IncreasesLevel()
    {
        _tracker.AddStock("SKU-A", 50);
        Assert.AreEqual(50, _tracker.GetStockLevel("SKU-A"));
    }

    [TestMethod]
    public void AddStock_MultiplAdds_Accumulates()
    {
        _tracker.AddStock("SKU-A", 20);
        _tracker.AddStock("SKU-A", 30);
        Assert.AreEqual(50, _tracker.GetStockLevel("SKU-A"));
    }

    [TestMethod]
    public void AddStock_DifferentSkus_TrackedIndependently()
    {
        _tracker.AddStock("SKU-A", 10);
        _tracker.AddStock("SKU-B", 25);

        Assert.AreEqual(10, _tracker.GetStockLevel("SKU-A"));
        Assert.AreEqual(25, _tracker.GetStockLevel("SKU-B"));
    }

    [TestMethod]
    public void RemoveStock_ReducesLevel()
    {
        _tracker.AddStock("SKU-A", 100);
        _tracker.RemoveStock("SKU-A", 40);
        Assert.AreEqual(60, _tracker.GetStockLevel("SKU-A"));
    }

    [TestMethod]
    public void RemoveStock_EntireStock_LeavesZero()
    {
        _tracker.AddStock("SKU-A", 50);
        _tracker.RemoveStock("SKU-A", 50);
        Assert.AreEqual(0, _tracker.GetStockLevel("SKU-A"));
    }

    [TestMethod]
    [ExpectedException(typeof(InvalidOperationException))]
    public void RemoveStock_MoreThanAvailable_Throws()
    {
        _tracker.AddStock("SKU-A", 10);
        _tracker.RemoveStock("SKU-A", 11);
    }

    [TestMethod]
    [ExpectedException(typeof(InvalidOperationException))]
    public void RemoveStock_FromEmptySku_Throws()
    {
        _tracker.RemoveStock("SKU-EMPTY", 1);
    }
}

[TestClass]
public class ValidationTests
{
    private InventoryTracker _tracker = null!;

    [TestInitialize]
    public void Setup() => _tracker = new InventoryTracker();

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void GetStockLevel_NullSku_Throws()
    {
        _tracker.GetStockLevel(null!);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void GetStockLevel_EmptySku_Throws()
    {
        _tracker.GetStockLevel("  ");
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentOutOfRangeException))]
    public void AddStock_ZeroQuantity_Throws()
    {
        _tracker.AddStock("SKU-A", 0);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentOutOfRangeException))]
    public void AddStock_NegativeQuantity_Throws()
    {
        _tracker.AddStock("SKU-A", -5);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentOutOfRangeException))]
    public void RemoveStock_ZeroQuantity_Throws()
    {
        _tracker.RemoveStock("SKU-A", 0);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentOutOfRangeException))]
    public void RemoveStock_NegativeQuantity_Throws()
    {
        _tracker.RemoveStock("SKU-A", -1);
    }
}

[TestClass]
public class ReorderAlertTests
{
    private InventoryTracker _tracker = null!;

    [TestInitialize]
    public void Setup() => _tracker = new InventoryTracker();

    [TestMethod]
    public void NeedsReorder_StockBelowDefaultThreshold_ReturnsTrue()
    {
        _tracker.AddStock("SKU-A", 5);
        Assert.IsTrue(_tracker.NeedsReorder("SKU-A"));
    }

    [TestMethod]
    public void NeedsReorder_StockAtDefaultThreshold_ReturnsTrue()
    {
        _tracker.AddStock("SKU-A", 10);
        Assert.IsTrue(_tracker.NeedsReorder("SKU-A"));
    }

    [TestMethod]
    public void NeedsReorder_StockAboveDefaultThreshold_ReturnsFalse()
    {
        _tracker.AddStock("SKU-A", 11);
        Assert.IsFalse(_tracker.NeedsReorder("SKU-A"));
    }

    [TestMethod]
    public void NeedsReorder_UnknownSku_ReturnsTrue()
    {
        Assert.IsTrue(_tracker.NeedsReorder("NEVER-STOCKED"));
    }

    [TestMethod]
    public void NeedsReorder_CustomThreshold_UsesSkuSpecificValue()
    {
        _tracker.SetReorderThreshold("SKU-A", 25);
        _tracker.AddStock("SKU-A", 20);
        Assert.IsTrue(_tracker.NeedsReorder("SKU-A"));
    }

    [TestMethod]
    public void NeedsReorder_CustomThreshold_AboveThreshold_ReturnsFalse()
    {
        _tracker.SetReorderThreshold("SKU-A", 5);
        _tracker.AddStock("SKU-A", 10);
        Assert.IsFalse(_tracker.NeedsReorder("SKU-A"));
    }

    [TestMethod]
    public void NeedsReorder_ChangedDefaultThreshold_Applies()
    {
        _tracker.ReorderThresholdDefault = 50;
        _tracker.AddStock("SKU-A", 40);
        Assert.IsTrue(_tracker.NeedsReorder("SKU-A"));
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentOutOfRangeException))]
    public void SetReorderThreshold_NegativeValue_Throws()
    {
        _tracker.SetReorderThreshold("SKU-A", -1);
    }

    [TestMethod]
    public void SetReorderThreshold_Zero_AllowsZeroThreshold()
    {
        _tracker.SetReorderThreshold("SKU-A", 0);
        _tracker.AddStock("SKU-A", 1);
        Assert.IsFalse(_tracker.NeedsReorder("SKU-A"));
    }
}

[TestClass]
public class WarehouseTransferTests
{
    private InventoryTracker _source = null!;
    private InventoryTracker _destination = null!;

    [TestInitialize]
    public void Setup()
    {
        _source = new InventoryTracker();
        _destination = new InventoryTracker();
    }

    [TestMethod]
    public void TransferStock_MovesFromSourceToDestination()
    {
        _source.AddStock("SKU-A", 100);
        _source.TransferStock("SKU-A", 30, _destination);

        Assert.AreEqual(70, _source.GetStockLevel("SKU-A"));
        Assert.AreEqual(30, _destination.GetStockLevel("SKU-A"));
    }

    [TestMethod]
    public void TransferStock_DestinationAlreadyHasStock_Accumulates()
    {
        _source.AddStock("SKU-A", 50);
        _destination.AddStock("SKU-A", 20);

        _source.TransferStock("SKU-A", 10, _destination);

        Assert.AreEqual(40, _source.GetStockLevel("SKU-A"));
        Assert.AreEqual(30, _destination.GetStockLevel("SKU-A"));
    }

    [TestMethod]
    public void TransferStock_EntireStock_LeavesSourceEmpty()
    {
        _source.AddStock("SKU-A", 25);
        _source.TransferStock("SKU-A", 25, _destination);

        Assert.AreEqual(0, _source.GetStockLevel("SKU-A"));
        Assert.AreEqual(25, _destination.GetStockLevel("SKU-A"));
    }

