        _destination = new InventoryTracker();
    }

    [TestMethod]
    public void TransferStock_MovesFromSourceToDestination()
    {
        _source.AddStock("SKU-A", 100);
        _source.TransferStock("SKU-A", 30, _destination);

        Assert.AreEqual(70, _source.GetStockLevel("SKU-A"));
        Assert.AreEqual(30, _destination.GetStockLevel("SKU-A"));
    }

    [TestMethod]
    public void TransferStock_DestinationAlreadyHasStock_Accumulates()
    {
        _source.AddStock("SKU-A", 50);
        _destination.AddStock("SKU-A", 20);

        _source.TransferStock("SKU-A", 10, _destination);

        Assert.AreEqual(40, _source.GetStockLevel("SKU-A"));
        Assert.AreEqual(30, _destination.GetStockLevel("SKU-A"));
    }

    [TestMethod]
    public void TransferStock_EntireStock_LeavesSourceEmpty()
    {
        _source.AddStock("SKU-A", 25);
        _source.TransferStock("SKU-A", 25, _destination);

        Assert.AreEqual(0, _source.GetStockLevel("SKU-A"));
        Assert.AreEqual(25, _destination.GetStockLevel("SKU-A"));
    }

    [TestMethod]
    public void TransferStock_InsufficientSource_Throws()
    {
        _source.AddStock("SKU-A", 10);
        Assert.ThrowsException<InvalidOperationException>(() =>
            _source.TransferStock("SKU-A", 20, _destination));
    }

    [TestMethod]
    public void TransferStock_ZeroQuantity_Throws()
    {
        _source.AddStock("SKU-A", 10);
        Assert.ThrowsException<ArgumentOutOfRangeException>(() =>
            _source.TransferStock("SKU-A", 0, _destination));
    }

    [TestMethod]
    public void TransferStock_NullDestination_Throws()
    {
        _source.AddStock("SKU-A", 10);
        Assert.ThrowsException<ArgumentNullException>(() =>
            _source.TransferStock("SKU-A", 5, null!));
    }

    [TestMethod]
    public void TransferStock_TriggersReorderOnSource()
    {
        _source.SetReorderThreshold("SKU-A", 15);
        _source.AddStock("SKU-A", 50);

        Assert.IsFalse(_source.NeedsReorder("SKU-A"));

        _source.TransferStock("SKU-A", 40, _destination);

        Assert.IsTrue(_source.NeedsReorder("SKU-A"));
    }

    [TestMethod]
    public void TransferStock_MultipleTransfers_MaintainsConsistency()
    {
        _source.AddStock("SKU-A", 100);

        _source.TransferStock("SKU-A", 20, _destination);
        _source.TransferStock("SKU-A", 30, _destination);
        _source.TransferStock("SKU-A", 10, _destination);

        Assert.AreEqual(40, _source.GetStockLevel("SKU-A"));
        Assert.AreEqual(60, _destination.GetStockLevel("SKU-A"));
