using Warehouse;

namespace Warehouse.Tests;

[TestClass]
public class StockLevelTests
{
    private InventoryTracker _tracker = null!;

    [TestInitialize]
    public void Setup() => _tracker = new InventoryTracker();

    [TestMethod]
    public void GetStockLevel_UnknownSku_ReturnsZero()
    {
        Assert.AreEqual(0, _tracker.GetStockLevel("UNKNOWN-001"));
    }

    [TestMethod]
    public void AddStock_SingleAdd_IncreasesLevel()
    {
        _tracker.AddStock("SKU-A", 50);
        Assert.AreEqual(50, _tracker.GetStockLevel("SKU-A"));
    }

    [TestMethod]
    public void AddStock_MultipleAdds_Accumulates()
    {
        _tracker.AddStock("SKU-A", 20);
        _tracker.AddStock("SKU-A", 30);
        Assert.AreEqual(50, _tracker.GetStockLevel("SKU-A"));
    }

    [TestMethod]
    public void AddStock_DifferentSkus_TrackedIndependently()
    {
        _tracker.AddStock("SKU-A", 10);
        _tracker.AddStock("SKU-B", 25);

        Assert.AreEqual(10, _tracker.GetStockLevel("SKU-A"));
        Assert.AreEqual(25, _tracker.GetStockLevel("SKU-B"));
    }

    [TestMethod]
    public void RemoveStock_ReducesLevel()
    {
        _tracker.AddStock("SKU-A", 100);
        _tracker.RemoveStock("SKU-A", 40);
        Assert.AreEqual(60, _tracker.GetStockLevel("SKU-A"));
    }

    [TestMethod]
    public void RemoveStock_EntireStock_LeavesZero()
    {
        _tracker.AddStock("SKU-A", 50);
        _tracker.RemoveStock("SKU-A", 50);
        Assert.AreEqual(0, _tracker.GetStockLevel("SKU-A"));
    }

    [TestMethod]
    public void RemoveStock_MoreThanAvailable_Throws()
    {
        _tracker.AddStock("SKU-A", 10);
        Assert.ThrowsException<InvalidOperationException>(() =>
            _tracker.RemoveStock("SKU-A", 11));
    }

    [TestMethod]
    public void RemoveStock_FromEmptySku_Throws()
